                    // Deep Dive link to Kahlo x Basquiat
                    Section(
                        id: "sec_mod_art_bonus",
                        title: "🎭 Bonus: Kahlo x Basquiat Deep Dive",
                        content: [
                            .callout(title: "Accidental Bedfellows", content: "Explore two of the world's greatest artists—Frida Kahlo and Jean-Michel Basquiat—through the lens of trauma, healing, and artistic expression. This deep dive examines how both artists transformed physical suffering into profound works of art.", type: .explore),
                            .text("This supplementary module explores the intersection of art, identity, and investment value through the lens of two artists who transcended their circumstances to create some of the most valuable works in modern art history.")
